const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
if (!SUPABASE_URL || !SUPABASE_KEY) throw new Error('Faltan variables de entorno: SUPABASE_URL y/o SUPABASE_SERVICE_KEY');
const staticData = $getWorkflowStaticData('global');
staticData.totalNuevos = 0;
staticData.totalDuplicados = 0;
staticData.cicloId = null;
let numeroCiclo = 1;
try {
  const ultimoCiclo = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/ciclos_actualizacion?select=numero_ciclo&order=numero_ciclo.desc&limit=1`, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } });
  if (Array.isArray(ultimoCiclo) && ultimoCiclo.length > 0) numeroCiclo = (ultimoCiclo[0].numero_ciclo || 0) + 1;
} catch (e) {}
const cicloResp = await this.helpers.httpRequest({ method: 'POST', url: `${SUPABASE_URL}/rest/v1/ciclos_actualizacion`, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation' }, body: JSON.stringify({ numero_ciclo: numeroCiclo, fecha_inicio: new Date().toISOString(), estado: 'en_proceso' }) });
const cicloId = Array.isArray(cicloResp) ? cicloResp[0].id : cicloResp.id;
staticData.cicloId = cicloId;
staticData.numeroCiclo = numeroCiclo;
return [{ json: { ciclo_id: cicloId, numero_ciclo: numeroCiclo, mensaje: `Ciclo ${numeroCiclo} iniciado` } }];

const fs = require('fs');
function parseLine(line) {
  const result = []; let current = ''; let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') { if (inQuotes && line[i+1] === '"') { current += '"'; i++; } else inQuotes = !inQuotes; }
    else if (ch === ',' && !inQuotes) { result.push(current); current = ''; }
    else current += ch;
  }
  result.push(current); return result;
}
const content = fs.readFileSync('/data/ferreterias.csv', 'utf8');
const lines = content.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
const headers = parseLine(lines[0]).map(h => h.trim().replace(/^\uFEFF/, ''));
const result = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i];
  if (!line.trim()) continue;
  const values = parseLine(line);
  const obj = {};
  headers.forEach((h, idx) => { obj[h] = values[idx] !== undefined ? values[idx].trim() : null; });
  result.push({ json: obj });
}
return result;

const items = $input.all();
function limpiar(str) {
  if (str === null || str === undefined || str === '' || str === 'null' || str === 'NULL') return null;
  return str.toString().trim().replace(/\s+/g, ' ') || null;
}
function parsearFecha(dateStr) {
  if (!dateStr) return null;
  const str = dateStr.toString().trim();
  if (!str || str === 'null' || str === 'NULL' || str === '0000-00-00') return null;
  const ddmmyyyy = str.match(/^(\d{1,2})[/-](\d{1,2})[/-](\d{4})$/);
  if (ddmmyyyy) { const [, d, m, y] = ddmmyyyy; return `${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`; }
  if (str.match(/^\d{4}-\d{2}-\d{2}$/)) return str;
  return null;
}
const resultado = items.filter(item => {
  const rs = item.json.razon_social || item.json.RAZON_SOCIAL || '';
  return rs.toString().trim().length > 0;
}).map(item => {
  const row = item.json;
  let repLegal = limpiar(row.representante_legal);
  if (!repLegal) { const n = limpiar(row.primer_nombre)||''; const a = limpiar(row.primer_apellido)||''; repLegal = `${n} ${a}`.trim()||null; }
  const razonSocial = limpiar(row.razon_social);
  const nit = limpiar(row.nit)||limpiar(row.numero_identificacion);
  const telefono = limpiar(row.telefono);
  const direccion = limpiar(row.direccion);
  const estadoMatricula = limpiar(row.estado_matricula)||'ACTIVA';
  const estadoInfo = (razonSocial && direccion && telefono) ? 'Completa' : 'Incompleta';
  const estadoLegal = (nit || estadoMatricula === 'ACTIVA') ? 'Legalmente constituida' : 'No legalmente constituida';
  return { json: {
    camara_comercio: limpiar(row.camara_comercio),
    razon_social: razonSocial,
    nit,
    organizacion_juridica: limpiar(row.organizacion_juridica),
    estado_matricula: estadoMatricula,
    fecha_matricula: parsearFecha(row.fecha_matricula),
    fecha_renovacion: parsearFecha(row.fecha_renovacion),
    representante_legal: repLegal,
    nombre_comercial: limpiar(row.nombre_comercial),
    direccion,
    ciudad: limpiar(row.ciudad)||limpiar(row.municipio),
    departamento: limpiar(row.departamento),
    telefono,
    email: limpiar(row.email),
    website: limpiar(row.website)||limpiar(row.sitio_web),
    estado_info: estadoInfo,
    estado_legal: estadoLegal,
    estado_actividad: 'Pendiente',
    fuente: 'camara_comercio',
    ciclo_actualizacion: $getWorkflowStaticData('global').numeroCiclo||1
  }};
});
return resultado;

const items = $input.all();
const staticData = $getWorkflowStaticData('global');
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
if (!SUPABASE_URL || !SUPABASE_KEY) throw new Error('Faltan variables de entorno');
const numeroCiclo = staticData.numeroCiclo||1;
const registros = items.map(item => {
  const f = item.json;
  return { camara_comercio: f.camara_comercio||null, razon_social: f.razon_social, nit: f.nit||null, organizacion_juridica: f.organizacion_juridica||null, estado_matricula: f.estado_matricula||'ACTIVA', fecha_matricula: f.fecha_matricula||null, fecha_renovacion: f.fecha_renovacion||null, representante_legal: f.representante_legal||null, nombre_comercial: f.nombre_comercial||null, direccion: f.direccion||null, ciudad: f.ciudad||null, departamento: f.departamento||null, telefono: f.telefono||null, email: f.email||null, website: f.website||null, estado_info: f.estado_info, estado_legal: f.estado_legal, estado_actividad: f.estado_actividad, fuente: f.fuente||'camara_comercio', ciclo_actualizacion: numeroCiclo };
});
let batchNuevos=0, batchDuplicados=0;
try {
  const resp = await this.helpers.httpRequest({ method: 'POST', url: `${SUPABASE_URL}/rest/v1/ferreterias`, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=ignore-duplicates,return=representation' }, body: JSON.stringify(registros) });
  batchNuevos = Array.isArray(resp) ? resp.length : 0;
  batchDuplicados = registros.length - batchNuevos;
} catch(err) { console.error(`Error upsert: ${err.message}`); }
staticData.totalNuevos = (staticData.totalNuevos||0) + batchNuevos;
staticData.totalDuplicados = (staticData.totalDuplicados||0) + batchDuplicados;
if (staticData.cicloId) {
  try { await this.helpers.httpRequest({ method: 'POST', url: `${SUPABASE_URL}/rest/v1/rpc/actualizar_ciclo`, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ p_ciclo_id: staticData.cicloId, p_nuevos: batchNuevos, p_duplicados: batchDuplicados }) }); } catch(e) {}
}
return [{ json: { batch_nuevos: batchNuevos, batch_duplicados: batchDuplicados, total_acumulado_nuevos: staticData.totalNuevos, total_acumulado_duplicados: staticData.totalDuplicados } }];

const staticData = $getWorkflowStaticData('global');
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const cicloId = staticData.cicloId;
if (cicloId) {
  await this.helpers.httpRequest({ method: 'POST', url: `${SUPABASE_URL}/rest/v1/rpc/finalizar_ciclo`, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ p_ciclo_id: cicloId }) });
}
const resumen = { ciclo_id: cicloId, numero_ciclo: staticData.numeroCiclo, total_nuevos: staticData.totalNuevos||0, total_duplicados: staticData.totalDuplicados||0, total_procesados: (staticData.totalNuevos||0)+(staticData.totalDuplicados||0), estado: 'completado', fecha_fin: new Date().toISOString() };
console.log('=== CARGA CSV COMPLETADA ===', JSON.stringify(resumen, null, 2));
return [{ json: resumen }];
